parameters.jsCode:
// Access guard + seed query.
// toPhone/caption may arrive top-level (Report API) or inside params (gateway smuggles them
// there because n8n drops newly added trigger fields). Either way a WhatsApp sender who is
// NOT an admin can only ever pull their OWN family's report - forced here in code.
const inp = $('Report Input').first().json || {};
let p = inp.params;
if (typeof p === 'string') { try { p = JSON.parse(p); } catch (e) { p = {}; } }
p = p || {};

const toPhone = String(inp.toPhone || p.toPhone || '').replace(/\D/g, '');
const requesterLast10 = toPhone.slice(-10);
let admins = [];
try { admins = $input.all().map(i => i.json).filter(j => j && j.phoneLast10); } catch (e) { admins = []; }
const isAdmin = admins.length > 0;
const isInternal = !toPhone;   // no sender at all -> internal/admin-panel caller -> trusted

let scopedToSelf = false;
if (!isInternal && !isAdmin) {
  if (!requesterLast10) return [{ json: { seedQuery: { __invalid: true }, requested: {}, denied: true } }];
  p = { phoneLast10: requesterLast10 };
  scopedToSelf = true;
}

const esc = (s) => String(s || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
// The AI passes what the admin typed, so "BHADANI family" arrives with the word attached.
const NOISE = /\b(family|families|parivar|paribar|kutumb|report|innka|inka|unka)\b/gi;
const clean = (s) => String(s || '').replace(NOISE, ' ').replace(/\s+/g, ' ').trim();

const q = {};
if (p.phoneLast10) q.phoneLast10 = String(p.phoneLast10).replace(/\D/g, '').slice(-10);
else if (p.groupName) q.groupName = String(p.groupName);
else if (clean(p.clientName)) {
  const term = clean(p.clientName);
  // A surname should find the family too, so match groupName as well as the client's own name.
  const rx = { $regex: esc(term).split(/\s+/).join('.*'), $options: 'i' };
  q.$or = [{ name: rx }, { groupName: rx }];
} else q.__invalid = true;
return [{ json: { seedQuery: q, requested: p, searchTerm: clean(p.clientName), isAdmin: isAdmin, isInternal: isInternal, scopedToSelf: scopedToSelf } }];

const seeds = $input.all().map(i => i.json).filter(j => j && j.name);
if (!seeds.length) return [{ json: { __error: 'No matching client found. Non-admin senders can only request their own family report.' } }];
const pr = $('Parse Request').first().json || {};
const req = pr.requested || {};
const norm = (s) => String(s || '').trim().toLowerCase().replace(/\s+/g, ' ');
const term = norm(pr.searchTerm || req.clientName);
const now = new Date();
const isInforce = (s) => {
  const mat = s.maturityDate ? new Date(s.maturityDate) : null;
  const matured = mat && !isNaN(mat) && mat < now;
  return !matured && s.isActive !== false;
};

// A surname spans several families here (BHADANI 6, BADRUKHIYA 8, KANANI 11). Picking the first
// would quietly hand the admin another family's financials, so ask unless the term names a
// client exactly or everything matched belongs to one family.
// A family means a groupName - rows without one are loose individuals, and counting each of
// those as its own family made every surname look ambiguous.
const exactHit = term && seeds.some(s => norm(s.name) === term);
const groups = {};
for (const s of seeds) {
  const g = (s.groupName && String(s.groupName).trim()) ? norm(s.groupName) : null;
  if (g) (groups[g] = groups[g] || []).push(s);
}
const gkeys = Object.keys(groups);
const ask = (opts, what) => {
  const lines = opts.slice(0, 8).map((o, i) => (i + 1) + '. ' + o.label + ' (' + o.members + ' members, ' + o.policies + ' policies)');
  return [{ json: { __error: 'Several ' + what + ' match "' + (pr.searchTerm || req.clientName || '') + '". Ask the admin which one they mean and list these options exactly as given, numbered:\n' + lines.join('\n') + '\nThey can reply with the number or the full name.' } }];
};
if (!exactHit && gkeys.length > 1) {
  const opts = gkeys.map(k => {
    const rows = groups[k];
    const head = rows.find(r => r.groupName) || rows[0];
    return { label: String(head.groupName || head.name).replace(/\s+/g, ' ').trim(), members: new Set(rows.map(r => r.name)).size, policies: rows.length };
  }).sort((a, b) => b.policies - a.policies);
  return ask(opts, 'families');
}
if (!exactHit && gkeys.length === 0) {
  const people = {};
  for (const s of seeds) (people[norm(s.name)] = people[norm(s.name)] || []).push(s);
  const pkeys = Object.keys(people);
  if (pkeys.length > 1) {
    const opts = pkeys.map(k => ({ label: String(people[k][0].name).replace(/\s+/g, ' ').trim(), members: 1, policies: people[k].length }))
      .sort((a, b) => b.policies - a.policies);
    return ask(opts, 'clients');
  }
}

seeds.sort((a, b) => {
  const ax = term && norm(a.name) === term ? 1 : 0;
  const bx = term && norm(b.name) === term ? 1 : 0;
  if (ax !== bx) return bx - ax;
  const ai = isInforce(a) ? 1 : 0, bi = isInforce(b) ? 1 : 0;
  if (ai !== bi) return bi - ai;
  const ag = a.groupName ? 1 : 0, bg = b.groupName ? 1 : 0;
  if (ag !== bg) return bg - ag;
  return (Number(b.sumAssured) || 0) - (Number(a.sumAssured) || 0);
});
const seed = seeds[0];
let famQuery, extraNames = [seed.name];
if (seed.groupName && String(seed.groupName).trim()) {
  famQuery = { groupName: seed.groupName };
} else if (Array.isArray(seed.familyMembers) && seed.familyMembers.length) {
  extraNames = [seed.name].concat(seed.familyMembers.map(f => f.name).filter(Boolean));
  famQuery = { name: { $in: extraNames } };
} else {
  famQuery = { name: seed.name };
}
const extraOr = [{ clientName: { $in: extraNames } }];
if (seed.phoneLast10) extraOr.push({ phoneLast10: seed.phoneLast10 });
return [{ json: { famQuery, extraQuery: { $or: extraOr }, familyHead: seed.name, groupName: seed.groupName || null, phoneLast10: seed.phoneLast10 || null, __seedPicked: seed.name, __seedCount: seeds.length } }];

const fq = $('Build Family Query').first().json;
if (fq.__error) return [{ json: { __error: fq.__error } }];
const cfg = $('Load Report Config').first().json || {};
const now = new Date();
const nowYear = now.getFullYear();
const mmm = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const licRows = $('Find Family Rows').all().map(i => i.json).filter(j => j && j.policyNo);
const extraRows = $('Find Extra Policies').all().map(i => i.json).filter(j => j && j.policyNo);
if (!licRows.length && !extraRows.length) return [{ json: { __error: 'No policies found for this family.' } }];
const planDocs = $('Find Plan Library').all().map(i => i.json).filter(j => j && (j.plan_table || j.docType));
const planMeta = planDocs.find(d => d.docType === 'meta') || {};
const DEF = planMeta.defaults || { fallback_method: 'endowment_par', fallback_srb_rate: 48, fallback_fab_rate: 0 };
const planMap = {};
for (const d of planDocs) if (d.plan_table) planMap[String(d.plan_table)] = d;

const bonusRates = $('Find Bonus Rates').all().map(i => i.json).filter(j => j && j.component);
const pmRows = $('Find Plan Master').all().map(i => i.json).filter(j => j && j.table_no);
const _aliasToBase = {}; const _master = {};
for (const p of pmRows) { _master[p.table_no] = p; if (p.relaunch_alias_no) _aliasToBase[p.relaunch_alias_no] = p.table_no; }
const _resolvePlan = (tbl) => { const t = Number(tbl) || 0; if (_master[t]) return t; if (_aliasToBase[t]) return _aliasToBase[t]; return t; };
const _fabPlanRows = {};
for (const r of bonusRates) if (r.component === 'FAB' && r.plan_no) { (_fabPlanRows[r.plan_no] = _fabPlanRows[r.plan_no] || []).push(r); }
const _stdFAB = [[15, 20], [16, 25], [20, 70], [21, 80], [25, 450], [40, 3550]];
const _fabForMethod = (m) => (m === 'endowment_par' || m === 'wholelife_endowment_par' || m === 'moneyback_par' || m === 'child_par' || m === 'wholelife_income_par');
const _fabLadder = (tbl, term, method) => {
  if (term < 15 || !_fabForMethod(method)) return 0;
  const pn = _resolvePlan(tbl);
  let rate = 0;
  const rows = _fabPlanRows[pn];
  if (rows && rows.length) { const sr = rows.slice().sort((a, b) => a.term_years - b.term_years); rate = Number(sr[0].rate_per_1000) || 0; for (const r of sr) if (r.term_years <= term) rate = Number(r.rate_per_1000) || 0; }
  else { for (const s of _stdFAB) if (s[0] <= term) rate = s[1]; }
  return rate;
};
const _isLakshya = (tbl) => _resolvePlan(tbl) === 833;

const runCalc = (method, params, inp) => {
  const srb = Number(params.srb_rate) || 0, fab = Number(params.fab_rate) || 0, ga = Number(params.ga_rate) || 0;
  const sched = params.survival_schedule || null;
  let survivalTotal = 0, sumPct = 0;
  if (Array.isArray(sched)) for (const s of sched) { const pct = Array.isArray(s) ? s[1] : (s.pct || 0); survivalTotal += pct * inp.BSA; sumPct += pct; }
  const fabAmt = (fab / 1000) * inp.BSA;
  const accrued = (srb / 1000) * inp.BSA * inp.years_elapsed;
  if (method === 'term') return { maturity: null, death: inp.BSA, basis: 'guaranteed' };
  if (method === 'endowment_par' || method === 'wholelife_endowment_par') {
    const srbFull = (srb / 1000) * inp.BSA * inp.term;
    const saDeath = Math.max(1.25 * inp.BSA, 7 * inp.AP);
    const floor = Math.max(saDeath, 1.05 * inp.premiums_paid);
    return { maturity: Math.round(inp.BSA + srbFull + fabAmt), death: Math.round(floor + accrued + fabAmt), postMaturityCover: method === 'wholelife_endowment_par' ? inp.BSA : 0, basis: 'guaranteed+illustrated' };
  }
  if (method === 'moneyback_par' || method === 'child_par') {
    const srbFull = (srb / 1000) * inp.BSA * inp.term;
    const matPct = 1 - sumPct;
    return { maturity: Math.round(matPct * inp.BSA + srbFull + fabAmt), death: Math.round(inp.BSA + accrued + fabAmt), survivalTotal: Math.round(survivalTotal), basis: 'guaranteed+illustrated' };
  }
  if (method === 'wholelife_income_par') {
    const srbFull = (srb / 1000) * inp.BSA * (inp.ppt || inp.term);
    return { maturity: Math.round(inp.BSA + srbFull + fabAmt), death: Math.round(inp.BSA + (srb / 1000) * inp.BSA * Math.min(inp.years_elapsed, inp.ppt || inp.term) + fabAmt), income: Math.round(0.08 * inp.BSA), basis: 'guaranteed+illustrated' };
  }
  if (method === 'nonpar_guaranteed') {
    const gaFull = (ga / 1000) * inp.BSA * inp.term;
    return { maturity: Math.round(inp.BSA + gaFull), death: Math.round(inp.BSA + (ga / 1000) * inp.BSA * inp.years_elapsed), basis: 'guaranteed' };
  }
  return null;
};

const modeX = (m) => { m = String(m || '').toLowerCase(); if (m.startsWith('year')) return 1; if (m.startsWith('half')) return 2; if (m.startsWith('quat') || m.startsWith('quar')) return 4; if (m.startsWith('month')) return 12; return 0; };
const matLabel = (d) => { if (!d) return '-'; const dt = new Date(d); if (isNaN(dt)) return String(d); return mmm[dt.getMonth()] + '-' + String(dt.getFullYear()).slice(2); };
const ageOf = (dob) => { if (!dob) return null; const d = new Date(dob); if (isNaN(d)) return null; let a = nowYear - d.getFullYear(); const md = new Date(now); md.setFullYear(d.getFullYear()); if (md < d) a--; return (a > 0 && a < 110) ? a : null; };

const pols = [];
for (const r of licRows) {
  const single = String(r.mode || '').toLowerCase().startsWith('single') || Number(r.ppt) === 1;
  const mat = r.maturityDate ? new Date(r.maturityDate) : null;
  let status = 'In-force';
  if (r.isActive === false) status = 'Lapsed';
  else if (mat && !isNaN(mat) && mat < now) status = 'Matured';
  const x = modeX(r.mode);
  const term = Number(r.term) || 0;
  const ppt = Number(r.ppt) || term;
  const start = r.commencementDate ? new Date(r.commencementDate) : null;
  let yearsElapsed = (start && !isNaN(start)) ? Math.floor((now - start) / 31557600000) : term;
  yearsElapsed = Math.max(0, Math.min(yearsElapsed, term));
  if (status === 'Matured') yearsElapsed = term;
  const perYear = single ? 0 : (Number(r.premium) || 0) * (x || 1);
  const premiumsPaid = single ? (Number(r.premium) || 0) : perYear * Math.min(yearsElapsed, ppt);
  const tbl = String(r.tableNo || '-');
  const plan = planMap[tbl];
  let planName = plan && plan.plan_name ? plan.plan_name : null;
  let est = null, basis = null, planConfirmed = false, method = null, params = null;
  if (plan && plan.calc && plan.calc.method) { method = plan.calc.method; params = Object.assign({}, plan.calc.params || {}); planConfirmed = true; }
  else { method = DEF.fallback_method; params = { srb_rate: DEF.fallback_srb_rate, fab_rate: DEF.fallback_fab_rate }; }
  const bsa = Number(r.sumAssured) || 0;
  const _fab = _fabLadder(tbl, term, method);
  params.fab_rate = Math.max(Number(params.fab_rate) || 0, _fab);
  if (bsa > 0 && term > 0 && method !== 'annuity' && method !== 'ulip') {
    est = runCalc(method, params, { BSA: bsa, AP: perYear || (Number(r.premium) || 0), term, ppt, years_elapsed: yearsElapsed, premiums_paid: premiumsPaid });
    if (est && est.maturity && _isLakshya(tbl)) est.maturity = Math.round(est.maturity + 0.10 * bsa);
    if (est) basis = est.basis + (planConfirmed ? '' : ' (plan to be confirmed - default legacy rate ' + (params.srb_rate || '') + '/1000 used)') + (_fab > 0 ? ' + FAB ' + _fab + '/1000' : '');
  }
  pols.push({
    member: String(r.name || 'Unknown').trim(), policyNo: String(r.policyNo), tbl,
    planName: planName || (planConfirmed ? 'Table ' + tbl : null), planConfirmed,
    kind: 'life', type: single ? 'Single' : 'Regular',
    sa: bsa, premium: Number(r.premium) || 0, perYear,
    single, singleAmt: single ? (Number(r.premium) || 0) : 0,
    start: r.commencementDate || null, maturity: r.maturityDate || null,
    matYear: (mat && !isNaN(mat)) ? mat.getFullYear() : null, matLabel: matLabel(r.maturityDate),
    status, dob: r.dob || null, mode: r.mode || '',
    estMaturity: est && est.maturity ? est.maturity : null,
    estDeath: est && est.death ? est.death : null,
    estBasis: basis, method
  });
}
for (const r of extraRows) {
  const t = String(r.policyType || '').toLowerCase();
  const kind = t === 'health' ? 'health' : (t === 'life' || t === 'term' ? 'life' : (t === 'sip' ? 'investment' : 'general'));
  pols.push({
    member: String(r.clientName || fq.familyHead).trim(), policyNo: String(r.policyNo), tbl: r.insurerName || '-',
    planName: r.insurerName || null, planConfirmed: true,
    kind, type: 'Regular', sa: Number(r.sumAssured) || 0, premium: Number(r.premium) || 0,
    perYear: Number(r.premium) || 0, single: false, singleAmt: 0,
    start: r.startDate || null, maturity: r.maturityDate || null,
    matYear: r.maturityDate ? new Date(r.maturityDate).getFullYear() : null, matLabel: matLabel(r.maturityDate),
    status: String(r.status || 'active') === 'active' ? 'In-force' : (String(r.status) === 'lapsed' ? 'Lapsed' : 'In-force'),
    dob: null, mode: 'Yearly', estMaturity: null, estDeath: null, estBasis: null, method: null
  });
}

const memberMap = {};
for (const p of pols) { (memberMap[p.member] = memberMap[p.member] || []).push(p); }
const members = Object.keys(memberMap).map((nm) => {
  const rows = memberMap[nm];
  const life = rows.filter(r => r.kind === 'life');
  const lifeIn = life.filter(r => r.status === 'In-force');
  const health = rows.filter(r => r.kind === 'health' && r.status === 'In-force');
  const upcoming = lifeIn.filter(r => r.matYear && r.matYear >= nowYear);
  upcoming.sort((a, b) => a.matYear - b.matYear);
  const nextY = upcoming.length ? upcoming[0].matYear : 0;
  const nextRows = upcoming.filter(r => r.matYear === nextY);
  const dobRow = rows.find(r => r.dob);
  return {
    name: nm, age: dobRow ? ageOf(dobRow.dob) : null, policies_count: rows.length,
    life_sa_total: life.reduce((s, r) => s + r.sa, 0),
    life_inforce: lifeIn.reduce((s, r) => s + r.sa, 0),
    est_maturity_inforce: lifeIn.reduce((s, r) => s + (r.estMaturity || r.sa), 0),
    health_cover: health.reduce((s, r) => s + r.sa, 0),
    annual_premium: rows.filter(r => r.status === 'In-force').reduce((s, r) => s + r.perYear, 0),
    single_premium: rows.reduce((s, r) => s + r.singleAmt, 0),
    next_maturity_year: nextY,
    next_maturity_amount: nextRows.reduce((s, r) => s + r.sa, 0),
    next_maturity_est: nextRows.reduce((s, r) => s + (r.estMaturity || r.sa), 0),
    low_cover_flag: false
  };
});
const maxCover = Math.max(...members.map(m => m.life_inforce), 1);
for (const m of members) m.low_cover_flag = m.life_inforce > 0 && m.life_inforce <= maxCover / 10;

const lifeAll = pols.filter(p => p.kind === 'life');
const lifeInf = lifeAll.filter(p => p.status === 'In-force');
const lifeMat = lifeAll.filter(p => p.status === 'Matured');
const healthIn = pols.filter(p => p.kind === 'health' && p.status === 'In-force');
const totals = {
  members: members.length, policies: pols.length,
  inforce_count: pols.filter(p => p.status === 'In-force').length,
  matured_count: pols.filter(p => p.status === 'Matured').length,
  life_sa_total: lifeAll.reduce((s, r) => s + r.sa, 0),
  life_inforce: lifeInf.reduce((s, r) => s + r.sa, 0),
  est_maturity_inforce: lifeInf.reduce((s, r) => s + (r.estMaturity || r.sa), 0),
  inforce_pct: 0, health_cover: healthIn.reduce((s, r) => s + r.sa, 0),
  annual_premium: pols.filter(p => p.status === 'In-force').reduce((s, r) => s + r.perYear, 0),
  single_premium: pols.reduce((s, r) => s + r.singleAmt, 0),
  matured_total: lifeMat.reduce((s, r) => s + r.sa, 0),
  unconfirmed_plans: lifeAll.filter(p => !p.planConfirmed).length
};
totals.inforce_pct = totals.life_sa_total ? Math.round(totals.life_inforce * 100 / totals.life_sa_total) : 0;

const tlMap = {};
for (const p of lifeAll) {
  if (!p.matYear) continue;
  const key = p.matYear + '|' + (p.status === 'Matured' ? 1 : 0);
  tlMap[key] = tlMap[key] || { year: p.matYear, amount: 0, amountEst: 0, matured: p.status === 'Matured', policy_count: 0 };
  tlMap[key].amount += p.sa; tlMap[key].amountEst += (p.estMaturity || p.sa); tlMap[key].policy_count += 1;
}
const timeline = Object.values(tlMap).sort((a, b) => a.year - b.year || (a.matured ? -1 : 1));
const upcomingTl = timeline.filter(t => !t.matured && t.year >= nowYear);
const big = upcomingTl.slice().sort((a, b) => b.amountEst - a.amountEst);
const fp = {
  next_year: upcomingTl.length ? upcomingTl[0].year : 0,
  next_amount: upcomingTl.length ? upcomingTl[0].amount : 0,
  next_amount_est: upcomingTl.length ? upcomingTl[0].amountEst : 0,
  upcoming_total: upcomingTl.reduce((s, t) => s + t.amount, 0),
  upcoming_total_est: upcomingTl.reduce((s, t) => s + t.amountEst, 0),
  matured_total: totals.matured_total,
  big_years: [big[0] ? { year: big[0].year, amount: big[0].amountEst } : { year: 0, amount: 0 }, big[1] ? { year: big[1].year, amount: big[1].amountEst } : { year: 0, amount: 0 }],
  soon_by: nowYear + 2,
  soon_total: upcomingTl.filter(t => t.year <= nowYear + 2).reduce((s, t) => s + t.amountEst, 0),
  future_years: upcomingTl.length
};
const scorecard = {
  life: { status: totals.life_inforce >= 5000000 ? 'strong' : (totals.life_inforce >= 1000000 ? 'moderate' : 'low'), label: '' },
  health: { status: totals.health_cover > 0 ? 'covered' : 'gap', label: '' }
};
const computed = { totals, members, timeline, financial_planning: fp, scorecard, familyHead: fq.familyHead };

const lines = pols.map(p => [p.member, p.policyNo, (p.planName || 'Tbl ' + p.tbl) + (p.planConfirmed ? '' : ' (UNCONFIRMED)'), p.method || '-', p.type + '/' + p.mode, 'SA ' + p.sa, 'Prem ' + p.premium, p.single ? 'one-time' : ('PerYr ' + p.perYear), 'Mat ' + p.matLabel, 'EstMaturity ' + (p.estMaturity || '-'), p.status].join(' | '));
const aiUserPrompt = 'Generate the CGPE family financial and insurance report JSON for the family below. IMPORTANT: all numeric aggregates have already been computed by the deterministic benefit engine and are provided - copy them exactly, do NOT recompute. EstMaturity figures include ILLUSTRATED bonus (SRB per plan + Final Additional Bonus from the LIC bonus tables; unconfirmed plans use a default legacy rate and are flagged) - always describe them as illustrated, not guaranteed. Your value-add: insights (3-5 compliant strings), scorecard labels, data_notes (must mention how many plans are unconfirmed/to-source if any).\n\nFamily head: ' + fq.familyHead + '\nReport date: ' + now.toDateString() + '\n\nPRECOMPUTED AGGREGATES (use exactly):\n' + JSON.stringify({ totals, members, financial_planning: fp, scorecard_status: { life: scorecard.life.status, health: scorecard.health.status } }) + '\n\nPolicy rows with plan-library enrichment:\n' + lines.join('\n') + '\n\nHealth/mediclaim: ' + (totals.health_cover > 0 ? 'present, cover ' + totals.health_cover : 'none on record') + '\nMutual fund / SIP: ' + (pols.some(p => p.kind === 'investment') ? 'present' : 'none on record');

return [{ json: {
  aiUserPrompt,
  reportSystemPrompt: cfg.reportSystemPrompt || 'You are a report writer. Output only valid JSON.',
  publicBaseUrl: cfg.publicBaseUrl || 'https://ai.cgpe.in/webhook',
  reportCss: cfg.reportCss || '',
  computedStr: JSON.stringify(computed),
  polsStr: JSON.stringify(pols)
} }];

/* CGPE Report Generator — new 8-page render core.
   Pure function: buildHtml(computed, pols, ai, opts) -> { html, reportId, genDate }
   Designed to be inlined into the n8n "Validate and Render" code node.
   Roles removed (no gender/relation in DB): members ordered by in-force life cover.
   Graceful for single-member families. */

// ---------- helpers ----------
const esc = (s) => String(s == null ? '' : s).replace(/[&<>"']/g, c => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c]));
const grpIN = (n) => { // Indian digit grouping on an integer string
  n = Math.round(Number(n) || 0);
  const neg = n < 0; n = Math.abs(n).toString();
  if (n.length <= 3) return (neg ? '-' : '') + n;
  let last3 = n.slice(-3), rest = n.slice(0, -3);
  rest = rest.replace(/\B(?=(\d{2})+(?!\d))/g, ',');
  return (neg ? '-' : '') + rest + ',' + last3;
};
const fmtIN = (n) => '₹' + grpIN(n);                     // ₹2,56,65,000
const shortIN = (n) => {                                  // ₹2.57 Cr / ₹66.83 L / ₹50,000 / ₹0
  n = Number(n) || 0;
  if (n >= 1e7) return '₹' + (n / 1e7).toFixed(2) + ' Cr';
  if (n >= 1e5) return '₹' + (n / 1e5).toFixed(2) + ' L';
  return '₹' + grpIN(n);
};
const chartVal = (n) => {                                 // 1.04Cr / 20.1L / 2.0L
  n = Number(n) || 0;
  if (n >= 1e7) return (n / 1e7).toFixed(2) + 'Cr';
  return (n / 1e5).toFixed(1) + 'L';
};
const initials = (name) => {
  const parts = String(name || '').trim().split(/\s+/).filter(Boolean);
  if (!parts.length) return '?';
  // LIC names are SURNAME FIRST MIDDLE; take first letters of the two "personal" tokens if available
  const pick = parts.length >= 3 ? [parts[1], parts[2]] : parts;
  return pick.slice(0, 2).map(p => p[0]).join('').toUpperCase();
};
const shortName = (name) => { // drop leading surname token for display where template does so
  const parts = String(name || '').trim().split(/\s+/).filter(Boolean);
  return parts.length >= 2 ? parts.slice(1).join(' ') : (parts[0] || '');
};

