// ============ Pillars 3 & 4 goal engine (per-family: windows, costs, gaps, SIP) ============
function computeGoals(M, TL, T, nowYear, cfg) {
  const CFG = Object.assign({
    childMaxAge: 30, retireAge: 60, eduLo: 17, eduHi: 22, schoolStart: 4, marriageAge: 28,
    inflEducation: 0.06, inflMarriage: 0.06, inflRetire: 0.06,
    collegeFull: 2000000, schoolPerYear: 150000, marriagePerChild: 4000000, retireMonthly: 100000,
    swr: 0.06, sipReturn: 0.11, retireBuffer: 3, floater: [1000000, 1500000]
  }, cfg || {});

  const infl = (a, r, y) => a * Math.pow(1 + r, Math.max(0, y));
  const sipM = (fv, r, y) => { if (fv <= 0 || y <= 0) return 0; const i = r / 12, n = Math.round(y * 12); return fv * i / (Math.pow(1 + i, n) - 1); };

  const mem = (M || []).filter(m => m && m.age != null);
  const kids  = mem.filter(m => m.age < CFG.childMaxAge);
  const heads = mem.filter(m => m.age >= CFG.childMaxAge && m.age <= CFG.retireAge + 2);

  // in-force, still-to-come maturities
  const mats = (TL || []).filter(t => !t.matured && t.year >= nowYear)
                         .map(t => ({ year: t.year, amt: (t.amountEst || t.amount || 0) }));

  // windows from ages
  const eduEnds = kids.filter(k => k.age < CFG.eduHi).map(k => nowYear + (CFG.eduHi - k.age));
  const eduSpan = eduEnds.length ? [nowYear, Math.max.apply(null, eduEnds)] : null;
  const marYears = kids.map(k => Math.max(nowYear, nowYear + (CFG.marriageAge - k.age)));
  const marSpan = marYears.length ? [Math.min.apply(null, marYears), Math.max.apply(null, marYears)] : null;
  const head60 = heads.map(h => nowYear + (CFG.retireAge - h.age));
  const retSpan = head60.length ? [Math.min.apply(null, head60) - CFG.retireBuffer, Math.max.apply(null, head60) + CFG.retireBuffer] : null;
  const retAnchor = head60.length ? head60.slice().sort((a, b) => a - b)[Math.floor(head60.length / 2)] : null;

  // bucket each maturity: education > marriage > retirement > generational
  let poolEdu = 0, poolMar = 0, poolRet = 0; const genAll = [];
  for (const m of mats) {
    if (eduSpan && m.year >= eduSpan[0] && m.year <= eduSpan[1]) poolEdu += m.amt;
    else if (marSpan && m.year >= marSpan[0] && m.year <= marSpan[1]) poolMar += m.amt;
    else if (retSpan && m.year >= retSpan[0] && m.year <= retSpan[1]) poolRet += m.amt;
    else genAll.push(m);
  }
  // generational split: match year to a member's ~age-100 year
  let genChild = 0, genParent = 0;
  for (const m of genAll) {
    const isChild = kids.some(k => Math.abs((nowYear + (100 - k.age)) - m.year) <= 6);
    if (isChild) genChild += m.amt; else genParent += m.amt;
  }

  // education need (remaining school + college per child, inflated to their year)
  let eduNeed = 0;
  for (const k of kids) {
    if (k.age >= CFG.eduHi) continue;
    const yrsCollegeLeft = CFG.eduHi - Math.max(k.age, CFG.eduLo);
    let need = CFG.collegeFull * (yrsCollegeLeft / (CFG.eduHi - CFG.eduLo));
    if (k.age < CFG.eduLo) need += CFG.schoolPerYear * (CFG.eduLo - Math.max(k.age, CFG.schoolStart));
    eduNeed += infl(need, CFG.inflEducation, (nowYear + (CFG.eduHi - k.age)) - nowYear);
  }
  const eduSurplus = poolEdu - eduNeed;

  // marriage need
  let marNeed = 0, lastMar = nowYear;
  for (const k of kids) {
    const yr = Math.max(nowYear, nowYear + (CFG.marriageAge - k.age));
    lastMar = Math.max(lastMar, yr);
    marNeed += infl(CFG.marriagePerChild, CFG.inflMarriage, yr - nowYear);
  }
  const marAvail = poolMar + Math.max(0, eduSurplus);
  const marGap = marNeed - marAvail;
  const marSip = sipM(Math.max(0, marGap), CFG.sipReturn, lastMar - nowYear);

  // retirement need
  let ret = null;
  if (retAnchor) {
    const yrs = retAnchor - nowYear;
    const monthly = infl(CFG.retireMonthly, CFG.inflRetire, yrs);
    const corpus = monthly * 12 / CFG.swr;
    const income = poolRet * CFG.swr / 12;
    const gap = corpus - poolRet;
    ret = {
      moneyback: poolRet, anchor: retAnchor,
      span: [Math.min.apply(null, head60), Math.max.apply(null, head60)],
      monthly: Math.round(monthly), corpus: Math.round(corpus),
      income: Math.round(income), gap: Math.round(gap),
      sip: Math.round(sipM(Math.max(0, gap), CFG.sipReturn, yrs))
    };
  }

  return {
    nKids: kids.length,
    education: { moneyback: poolEdu, need: Math.round(eduNeed), surplus: Math.round(eduSurplus),
                 type: eduSurplus >= 0 ? 'surplus' : 'gap', hasWindow: !!eduSpan },
    marriage:  { moneyback: poolMar, need: Math.round(marNeed), avail: Math.round(marAvail),
                 gap: Math.round(marGap), sip: marSip ? Math.round(marSip) : 0,
                 type: marGap <= 0 ? 'surplus' : 'gap', span: marSpan },
    retirement: ret,
    generational: { child: genChild, parent: genParent },
    health: { gap: (T.health_cover || 0) <= 0, floater: CFG.floater }
  };
}

// buildHtml(computed, pols, ai, genDate) -> html string
function buildHtml(computed, pols, ai, genDate) {
  const T = computed.totals, M = (computed.members || []).slice(), TL = computed.timeline || [];
  const FP = computed.financial_planning || {}, SC = computed.scorecard || { life: {}, health: {} };
  const head = computed.familyHead || 'Family';
  ai = ai || {};
  const disclaimer = 'Prepared by CGPE from supplied policy data · Cover figures are base sum assured; estimated values include illustrated bonus (not guaranteed) · Verify against policy bonds · Information summary, not financial advice.';

  // members ordered by in-force life cover (no roles — DB has no relation/gender)
  M.sort((a, b) => (b.life_inforce || 0) - (a.life_inforce || 0));
  const isSolo = T.members <= 1;
  const umangCount = pols.filter(p => /umang/i.test(p.planName || '')).length;

  const rhead = (rtitle) => `<div class="rhead"><div class="lft"><div class="em">${LOGO('dark')}</div>`
    + `<div><div class="wm">CGP ENTERPRISE</div><div class="sub">Nurturing Wealth, Securing Future</div></div></div>`
    + `<div class="rgt"><b>${esc(rtitle)}</b>${esc(shortHead(head))} · Surat</div></div>`;
  const rfoot = (pg, total) => `<div class="rfoot"><div>${esc(disclaimer)}</div><div class="pg">Page ${pg} / ${total}</div></div>`;
function shortHead(h) { return String(h || '').split(/\s+/).slice(0, 2).join(' '); }

  // ---- schedule pagination (compute page count first) ----
  const byMember = {};
  for (const p of pols) { (byMember[p.member] = byMember[p.member] || []).push(p); }
  const memberOrder = M.map(m => m.name).filter(nm => byMember[nm]);
  for (const nm of Object.keys(byMember)) if (!memberOrder.includes(nm)) memberOrder.push(nm);
  const ROW_BUDGET = 26;                     // approx table-row units per schedule page
  const schedulePages = [];
  let cur = [], used = 0;
  for (const nm of memberOrder) {
    const rows = byMember[nm];
    const cost = 3 + rows.length;            // band + header + rows
    if (used + cost > ROW_BUDGET && cur.length) { schedulePages.push(cur); cur = []; used = 0; }
    cur.push(nm); used += cost;
  }
  if (cur.length) schedulePages.push(cur);
  if (!schedulePages.length) schedulePages.push([]);
  const TOTAL = 5 + schedulePages.length;
  const schedStart = 6, schedEnd = TOTAL;

  // ===================== PAGE 1 — COVER =====================
  const statChip = (lab, val) => `<div style="background:rgba(255,255,255,.07);border:1px solid rgba(255,255,255,.14);border-radius:9px;padding:9px 14px">`
    + `<div style="font-size:7.5px;letter-spacing:1.2px;text-transform:uppercase;color:#9aa2cf;font-weight:600">${lab}</div>`
    + `<div style="font-family:'Playfair Display',serif;font-weight:700;font-size:15px;margin-top:2px">${val}</div></div>`;
  const cover = `<div class="page" style="padding:0;background:var(--navy);color:#fff;display:flex;flex-direction:column">
    <div style="position:absolute;inset:0;background:radial-gradient(120% 80% at 85% 8%, rgba(130,176,79,.18), transparent 55%),radial-gradient(90% 70% at 12% 96%, rgba(46,123,193,.20), transparent 55%),linear-gradient(160deg,#2a3270,#1b2150)"></div>
    <div style="position:relative;padding:22mm 22mm 0;flex:1;display:flex;flex-direction:column">
      <div style="display:flex;justify-content:space-between;align-items:flex-start">
        <div><div style="font-size:9px;letter-spacing:3.5px;color:var(--leaf);font-weight:700;text-transform:uppercase">CGP Enterprise · Surat · Since 1989</div>
          <div style="font-size:8.5px;letter-spacing:2.5px;color:#aeb6e0;font-weight:600;text-transform:uppercase;margin-top:10px">Family Financial &amp; Insurance Report</div></div>
        <div class="em" style="width:74px;height:74px">${LOGO('light')}</div></div>
      <div style="margin-top:16mm">
        <div style="font-family:'Playfair Display',serif;font-weight:800;font-size:37px;line-height:1.08;letter-spacing:-.3px">${esc(head)}</div>
        <div style="font-family:'Playfair Display',serif;font-style:italic;font-weight:500;font-size:19px;color:#cdd3ef;margin-top:6px">${isSolo ? 'Individual portfolio' : 'Family · ' + T.members + ' members'}</div>
        <div style="width:64px;height:4px;background:var(--leaf);border-radius:3px;margin:18px 0"></div>
        <div style="font-family:'Playfair Display',serif;font-size:17px;color:var(--leaf);font-weight:600">Nurturing Wealth, Securing Future</div>
        <div style="color:#c3c9ec;font-size:10px;max-width:122mm;margin-top:12px;line-height:1.6">A complete, plain-language view of your ${isSolo ? '' : "family's "}protection, savings and wealth plan — built on the four pillars of financial planning, prepared for you by your CGPE Family CFO.</div></div>
      <div style="margin-top:auto;padding-bottom:8mm"><div style="display:flex;gap:10px;flex-wrap:wrap">
        ${statChip('Members', T.members)}${statChip('Policies', T.policies)}${statChip('In-force cover', shortIN(T.life_inforce))}${statChip('Generated', genDate)}</div></div>
    </div>
    <div style="position:relative;background:rgba(0,0,0,.16);border-top:2px solid var(--leaf);padding:12px 22mm;display:flex;justify-content:space-between;align-items:center">
      <div><div style="font-family:'Playfair Display',serif;font-weight:800;font-size:14px;letter-spacing:.5px">CGP ENTERPRISE</div>
        <div style="font-size:8px;color:#aeb6e0;margin-top:2px">Insurance &amp; Financial Planning · Surat · Confidential</div></div>
      <div style="text-align:right;font-size:7.5px;color:#8f97c4;max-width:62mm;line-height:1.5">Information summary, not financial advice. Verify all figures against your policy bonds.</div></div>
  </div>`;

  // ===================== PAGE 2 — FOUR PILLARS =====================
  const lifeChip = SC.life.status === 'strong' ? '<span class="chip ok">Strong</span>'
    : SC.life.status === 'moderate' ? '<span class="chip ok">Moderate</span>' : '<span class="chip gap">Low</span>';
  const healthChip = T.health_cover > 0 ? '<span class="chip ok">Covered</span>' : '<span class="chip gap">Gap</span>';
  const p2 = `<div class="page">${rhead('Family Financial Report')}
    <div class="eyebrow">Your Complete Financial Plan</div><h2 class="sec-title">The four pillars of your ${isSolo ? '' : "family's "}plan <span class="guj">— Chaar aadhaar-stambh</span></h2>
    <p class="lede">Complete financial security stands on four pillars. The first two <b>secure</b> what you have; the next two <b>nurture</b> and grow it for the years ahead. Here is where you stand on each today.</p>
    <div class="grp-label secure"><span class="bar"></span><span class="t">Secure · protect what you have</span></div>
    <div class="pgrid"><div class="pcard secure"><div class="ph"><div class="num">1</div><div><div class="pname">Life Insurance</div><div class="pguj">Jeevan Vima</div></div></div>
        <div class="pwhat">Money your family receives if something happens to a covered member.</div>
        <div class="pstat">${lifeChip}<span class="pval">${shortIN(T.life_inforce)} in-force</span></div>
        <div class="pnote">${T.inforce_count} active ${T.inforce_count === 1 ? 'policy' : 'policies'}${isSolo ? '' : ' across ' + T.members + ' members'}.</div></div>
      <div class="pcard secure"><div class="ph"><div class="num">2</div><div><div class="pname">Health Insurance</div><div class="pguj">Mediclaim / Aarogya Vima</div></div></div>
        <div class="pwhat">Cover for hospitalization and medical bills — separate from life cover.</div>
        <div class="pstat">${healthChip}<span class="pval">${T.health_cover > 0 ? shortIN(T.health_cover) + ' cover' : '₹0 on record'}</span></div>
        <div class="pnote">${T.health_cover > 0 ? 'Health cover is on record.' : 'No health policy on record. The clearest gap — review first.'}</div></div></div>
    <div class="grp-label nurture"><span class="bar"></span><span class="t">Nurture · grow what you build</span></div>
    <div class="pgrid"><div class="pcard nurture"><div class="ph"><div class="num">3</div><div><div class="pname">Goal &amp; Life-Event Planning</div><div class="pguj">Jivan-na prasang-nu aayojan</div></div></div>
        <div class="pwhat">Planning by age for education, marriage, and retirement income after 60.</div>
        <div class="pstat"><span class="chip grow">In progress</span><span class="pval">${shortIN(T.est_maturity_inforce)} est. maturity</span></div>
        <div class="pnote">Money-back timed to life goals and retirement. Mapped next page.</div></div>
      <div class="pcard nurture"><div class="ph"><div class="num">4</div><div><div class="pname">Generational Wealth</div><div class="pguj">Pedhi dar pedhi sampatti</div></div></div>
        <div class="pwhat">Growing and passing wealth to the next generation — the HNI pillar.</div>
        <div class="pstat"><span class="chip grow">${umangCount > 0 ? 'Started' : 'To start'}</span><span class="pval">${umangCount > 0 ? umangCount + ' next-gen ' + (umangCount === 1 ? 'policy' : 'policies') : 'Not yet started'}</span></div>
        <div class="pnote">${umangCount > 0 ? umangCount + ' Jeevan Umang ' + (umangCount === 1 ? 'policy builds' : 'policies build') + ' long-term wealth; add investments &amp; nominations.' : 'Consider long-term wealth-building plans and nominations.'}</div></div></div>
    <div class="through"><div class="th-hd">The through-line</div><p>This maps to our promise — <b>Nurturing Wealth, Securing Future.</b> Life &amp; Health <b>secure</b> your family; goal planning &amp; generational wealth <b>nurture</b> it. A complete plan needs all four.</p></div>
    <div class="toc"><div class="toc-hd">What's inside — where to find the detail</div><div class="toc-grid">
      <div class="toc-item"><span class="pg">Page 3</span><span class="tx">Protection — Life &amp; Health cover${isSolo ? '' : ', member by member'}</span></div>
      <div class="toc-item"><span class="pg">Page 4</span><span class="tx">Goals — education, marriage, retirement &amp; generational wealth</span></div>
      <div class="toc-item"><span class="pg">Page 5</span><span class="tx">${isSolo ? 'Portfolio at a glance and totals' : 'Each of the ' + T.members + ' members at a glance, and family totals'}</span></div>
      <div class="toc-item"><span class="pg">${schedStart === schedEnd ? 'Page ' + schedStart : 'Pages ' + schedStart + '–' + schedEnd}</span><span class="tx">Every policy on record, grouped by member</span></div></div></div>
    ${rfoot(2, TOTAL)}</div>`;

  // ===================== PAGE 3 — PROTECTION =====================
  const barMembers = M.filter(m => (m.life_inforce || 0) > 0 || (m.life_sa_total || 0) > 0).slice(0, 10);
  const maxCover = Math.max(1, ...barMembers.map(m => m.life_inforce || 0));
  const bars = barMembers.map(m => {
    const pct = Math.max(2, ((m.life_inforce || 0) * 100 / maxCover)).toFixed(1);
    const ageTxt = m.age ? m.age + ' yrs' : 'age n/a';
    return `<div class="bar-row"><div class="nm">${esc(shortName(m.name))}<span>${ageTxt}</span></div>`
      + `<div class="track"><div class="fill" style="width:${pct}%"></div></div><div class="val">${shortIN(m.life_inforce || 0)}</div></div>`;
  }).join('');
  function shortName(n) { const p = String(n || '').trim().split(/\s+/); return p.length >= 2 ? p.slice(1).join(' ') : (p[0] || ''); }
  const reviewItems = (ai.insights && ai.insights.length ? ai.insights : defaultInsights(T, FP)).slice(0, 6)
    .map(s => `<li>${esc(s)}</li>`).join('');
  const p3 = `<div class="page">${rhead('Family Financial Report')}
    <div class="eyebrow">Pillars 1 &amp; 2 · Protection</div><h2 class="sec-title">How protected are you? <span class="guj">— Ketla surakshit chho?</span></h2>
    <p class="lede">Two kinds of protection matter: <b>Life</b> (money your family receives if something happens to a member) and <b>Health</b> (cover for hospital &amp; medical bills). Here is where you stand today.</p>
    <div class="panel"><div class="panel-hd">
        <div><div class="k">Life insurance · Jeevan Vima</div><h3>What your family receives, in-force</h3><div class="desc">Money payable if something happens to a covered member.</div></div>
        <div><div class="bignum"><span class="cur">₹</span>${grpIN(T.life_inforce)}</div>
          <div class="rgt-note">in-force base cover · ${T.inforce_pct}% of ${fmtIN(T.life_sa_total)} total<br>est. value incl. bonus (illustrated): <b>${shortIN(T.est_maturity_inforce)}</b></div></div></div>
      <div class="bars">${bars || '<div style="font-size:9px;color:var(--muted)">No in-force life cover on record.</div>'}</div>
      <div class="bars-note">Bars show each member's in-force base life cover.${T.matured_total > 0 ? ' ' + shortIN(T.matured_total) + ' from ' + T.matured_count + ' ' + (T.matured_count === 1 ? 'policy has' : 'policies have') + ' already matured and been paid out.' : ''}</div></div>
    <div class="gap-panel"><div class="panel-hd">
        <div><div class="k">Health insurance · Mediclaim / Aarogya Vima</div><h3>Cover for hospitalization &amp; medical bills</h3></div>
        <div><div class="bignum"><span class="cur">₹</span>${grpIN(T.health_cover)}</div><div class="rgt-note" style="color:#b07360">${T.health_cover > 0 ? 'health cover on record' : 'no health policy on record'}</div></div></div>
      ${T.health_cover > 0 ? '' : '<div class="gap-band">No health cover on record' + (isSolo ? '' : ' — all ' + T.members + ' members') + '</div><div class="gap-msg"><b>This is the clearest gap.</b> Medical and hospital bills are currently <b>not insured</b> — in Surat a single serious hospitalization can cost several lakhs. Worth reviewing a family floater with your CGPE adviser.</div>'}</div>
    <div class="status-row">
      <div class="stile"><div class="ic ${T.life_inforce > 0 ? 'ok' : 'no'}">${T.life_inforce > 0 ? '&#10003;' : '&#10005;'}</div><div><div class="lab">Life protection</div><div class="big">${T.life_inforce >= 5000000 ? 'Strong' : T.life_inforce > 0 ? 'Moderate' : 'None'} · ${shortIN(T.life_inforce)}</div></div></div>
      <div class="stile ${T.health_cover > 0 ? '' : 'gapt'}"><div class="ic ${T.health_cover > 0 ? 'ok' : 'no'}">${T.health_cover > 0 ? '&#10003;' : '&#10005;'}</div><div><div class="lab">Health protection</div><div class="big">${T.health_cover > 0 ? 'Covered · ' + shortIN(T.health_cover) : 'Gap · ₹0 on record'}</div></div></div></div>
    <div class="review card mist grn-rule"><div class="hd">Points to review with your CGPE adviser <small>— information only, not financial advice</small></div><ul>${reviewItems}</ul></div>
    ${rfoot(3, TOTAL)}</div>`;

  // ===================== PAGE 4 — GROWING WEALTH =====================
  const kNext = FP.next_year ? `<div class="kpi hl"><div class="top"></div><div class="kl">Next money-back</div><div class="kv">${FP.next_year}</div><div class="ks">est ${shortIN(FP.next_amount_est)} (base ${shortIN(FP.next_amount)})</div></div>`
    : `<div class="kpi hl"><div class="top"></div><div class="kl">Next money-back</div><div class="kv">—</div><div class="ks">none upcoming on record</div></div>`;
  const kpis4 = kNext
    + `<div class="kpi"><div class="top"></div><div class="kl">Coming back (est, in-force)</div><div class="kv grn">${shortIN(T.est_maturity_inforce)}</div><div class="ks">base ${shortIN(T.life_inforce)}</div></div>`
    + `<div class="kpi"><div class="top"></div><div class="kl">Already received</div><div class="kv">${shortIN(T.matured_total)}</div><div class="ks">${T.matured_count} matured ${T.matured_count === 1 ? 'policy' : 'policies'} (base)</div></div>`
    + `<div class="kpi"><div class="top"></div><div class="kl">You pay / year</div><div class="kv">${shortIN(T.annual_premium)}</div><div class="ks">recurring premium</div></div>`;
  // chart from timeline
  const tlShow = TL.slice().sort((a, b) => a.year - b.year).slice(0, 14);
  const maxTl = Math.max(1, ...tlShow.map(t => t.amountEst || 0));
  const cols = tlShow.map(t => {
    const h = Math.max(3, (t.amountEst || 0) * 100 / maxTl).toFixed(1);
    const big = (t.amountEst || 0) === maxTl;
    const paid = t.matured;
    return `<div class="col${big ? ' big' : ''}"><div class="cval">${chartVal(t.amountEst || 0)}</div><div class="cbar" style="height:${h}%${paid ? ';background:#dfe3ec' : ''}"></div></div>`;
  }).join('');
  const xax = tlShow.map(t => `<div class="xc">${t.year}</div>`).join('');
  const bigYears = (FP.big_years || []).filter(b => b && b.year);
